const express = require('express');
const app = express();

app.post('/notifications', async (req, res) => {
  const notificationData = req.body;
  const notificationTemplate = await getNotificationTemplate(notificationData.templateId);
  const userPreferences = await getUserPreferences(notificationData.userId);

  const notificationProvider = getNotificationProvider(notificationData.channel);
  await notificationProvider.sendNotification(notificationData, notificationTemplate, userPreferences);

  res.send('Notification sent successfully');
